module sr_latch (
    input wire invalid_S,
    input wire R,
    output reg Q,
    output wire Q_not
);
    assign Q_not = ~Q;

    always @(invalid_S or R) begin
        if (invalid_S && ~R) begin
            Q <= 1'b1; // Set
        end else if (~invalid_S && R) begin
            Q <= 1'b0; // Reset
        end else if (~invalid_S && ~R) begin
            // Maintain state
            Q <= Q;  
        end else begin
            // Invalid state (invalid_S = 1, R = 1)
            Q <= Q;  
        end
    end
endmodule
